function bit(cols: readonly string[], gx: number, gz: number): boolean {
  const col = cols[gx];
  if (col === undefined || gz < 0) return false;
  const nibble = col.charCodeAt(gz >> 2);
  const val = nibble <= 57 ? nibble - 48 : nibble - 87;
  return (val & (8 >> (gz & 3))) !== 0;
}

